var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"거긴 어때? 뭐 찾은 거 있어?","JPN":"どう？　何か目ぼしいものはあった？","ENG":"How's it looking over there? Did you find anything?","TWN":"那邊怎麼樣？有找到什麼嗎？"},"stage":{"bg":"SNOWYARD_01","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"아뇨. 적철도, 사람 흔적도 발견하지 못했습니다.","JPN":"いいえ、赤鉄も、人の痕跡も見当たりませんでした。","ENG":"No. No signs of Violarite or humans.","TWN":"沒有，連個人影也沒看見，更不用說赤鐵。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"이곳이 도시였다는 걸 증명하는 건 우리가 밟고 다니는 지붕이 전부입니다.","JPN":"ここがかつて都市だったという証拠となるのは、私たちが踏んでいる屋根しかありません。","ENG":"The roofs we are currently walking on are the only evidence that this was once a city.","TWN":"能證明這裡曾經是城市的，只有我們腳下踩的這些屋頂。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"어쩌면 20년동안 내린 눈 때문에 아래에 전부 묻혔을지도 모르지요.","JPN":"もしかすると、20年も降り続けた雪のせいで、なにもかもが埋もれてしまっているのかもしれません。","ENG":"Perhaps everything is buried underneath after twenty years of snow.","TWN":"或許是20年來不斷地積雪，東西可能都埋在這底下。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"쳇, 그럼 이 넓은 곳을 어디서부터 파헤쳐야 하는 거지?","JPN":"ちっ、こんなに広大な場所、どこから掘り起こせばいいのよ。","ENG":"Tch. Then where are we supposed to start digging in this large area?","TWN":"嘖，這麼大的地方，是要從哪裡開始挖起？"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"저기, 모르가나…","JPN":"あの、モルガナ……","ENG":"Um, Morgana...","TWN":"那個，莫甘娜…"},"stage":{"bg":"SNOWYARD_01","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"무슨 일이야? 황소허벅지.","JPN":"どうしたの？　大根足。","ENG":"What is it, thick thighs?","TWN":"什麼事，蜜大腿？"},"stage":{"bg":"SNOWYARD_01","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"아하하…","JPN":"あはは……","ENG":"Ah hah hah...","TWN":"哈哈…"},"stage":{"bg":"SNOWYARD_01","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"20년 전의 조사단 사람들은 동토에 내리는 눈이 녹지도 그치지도 않는단 걸 알고 있었겠죠?","JPN":"20年前に来た調査団の方々は凍土の雪は解けることも降り止むこともないことは知っていましたよね？","ENG":"The survey corps from twenty years ago was also aware that the snow in the gelid lands doesn't melt or stop falling, right?","TWN":"20年前的調查員應該都知道這裡的雪既不會融化，也不會停止吧？"},"stage":{"bg":"SNOWYARD_01","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐?","JPN":"はあ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"SNOWYARD_01","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그야 당연하잖아. 그 정도는 그루터기의 꼬맹이들도 아는 사실이라고.","JPN":"当たり前でしょ。そんなこと切り株のガキたちだって知っているわよ。","ENG":"Of course. Even the kids at the Stump know that.","TWN":"那當然，這種事連木墩的小孩子都知道。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"만약 그런 분들이 훗날 저희가 올 걸 대비해 뭔가를 남겼다면…","JPN":"もしかしたらその方たちは、私たちがここに来ることを予想して、何かを残していたとしたら……","ENG":"Then, if they left something in anticipation that we'd come for them one day...","TWN":"那些人若是要為將來的我們留下些什麼資訊…"},"stage":{"bg":"SNOWYARD_01","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"아마도 눈이 쌓이지 않을 가장 높은 장소를 고르지 않았을까… 라는 생각이 들어서요.","JPN":"おそらく雪が積もることのない、一番高い場所を選んだんじゃないかなって……思いつきまして。","ENG":"I think they would've picked the highest location... where snow wouldn't pile up.","TWN":"應該會選擇留在一個不會積雪的至高點吧…"},"stage":{"bg":"SNOWYARD_01","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SNOWYARD_01","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"좋아. 확인해보자.","JPN":"よし、調べてみよう。","ENG":"Okay. Let's go check it out.","TWN":"好，去確認一下吧。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"여깁니다! 이 첨탑이 일대에서 가장 높은 건축물이예요.","JPN":"ここです！　この尖塔がこの一帯では一番高い建物になります。","ENG":"Over here! The spire is the tallest structure here.","TWN":"就是這裡！這座尖塔是這一帶最高的建築物。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"이건 등대잖아?","JPN":"これは灯台じゃない！？","ENG":"This is a lighthouse, isn't it?","TWN":"這是燈塔吧？"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"등대가 뭐죠?","JPN":"灯台って何ですか？","ENG":"What's a lighthouse?","TWN":"什麼是燈塔？"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"어둠 속에서 배가 길을 잃지 않게 해주는 탑이야. 바다와 맞닿은 도시엔 적어도 하나씩 있지.","JPN":"暗い中でも船が進行方向を見失わないようにしてくれる塔のことよ。港町には必ずあるの。","ENG":"It's a tower that prevents boats from getting lost in the dark. There is at least one in every city facing the sea.","TWN":"就是讓在黑暗中航行的船隻不至於迷路的高塔，每個靠海的城市都至少會有一座。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모르가나는 전에도 이런 걸 본 적이 있어요?","JPN":"モルガナは以前にも同じものを見たことがあるんですか？","ENG":"Have you ever seen one before, Morgana?","TWN":"莫甘娜，這你以前見過嗎？"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"본 적은 없지만 배웠어.","JPN":"見たことはないけれど、習ったのよ。","ENG":"I haven't, but I learned about it.","TWN":"沒親眼見過，但在課本上學過。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"멀린 같은 드루이드가 되려면 아발론의 역사를 비롯해 많은 지식을 알고 있어야 하니까.","JPN":"マーリンのようなドロイドになるためには、アバロンの歴史を含め、様々な知識に精通していなければならないから。","ENG":"I need to be knowledgeable in Avalon's history if I want to become a Druid like Merlin.","TWN":"要成為像梅林那樣的德魯伊，從阿瓦隆的歷史，到其他相關的知識都必須知道。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그 지식이 당장은 별 쓸모없을 것 같아도… 결국엔 다 쓸모가 있거든.","JPN":"その知識がすぐに使えるものではなくても……いつか役に立つときが来るからね。","ENG":"Even if it doesn't seem useful at the time... they all have some use in the end.","TWN":"就算當下可能無法學以致用…但終究會派上用場的。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"등대의 입구가 보이지 않는군요. 눈 아래에 파묻혀버린 모양입니다.","JPN":"灯台の入口が見当たりませんね。雪に埋もれてしまったんでしょう。","ENG":"I can't find the entrance to the lighthouse. It seems to be buried in the snow.","TWN":"看不到燈塔的入口，似乎是被埋在積雪底下。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"꼭대기만 확인해볼 수 있으면 좋겠지만, 저길 무슨 수로 올라가죠?","JPN":"天辺だけでも確認したいのですが、あんなところまでどうやって登りましょうか？","ENG":"It would be best to just check the top, but how do we get up there?","TWN":"真想去塔頂看看，但是要怎麼上去呢…？"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"쳇… 미끄러워서 벽을 타기도 쉽지 않겠네.","JPN":"ちっ……滑りやすくて壁面を登るのも難しそうね。","ENG":"Tch... I guess climbing the wall won't be easy because it's so slippery.","TWN":"嘖…塔面這麼滑也不太好爬。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};